mapper.insert:
		/*
             SQL ID : ExamStarePaperDAO.insertExamStarePaper
            	 설  명 : 응시 시험지 등록
         */
    	INSERT INTO TB_LMS_EXAM_STARE_PAPER (
    		  EXAM_ID
			, EXAM_QSTN_NO
			, STD_ID
			, QSTN_SEQNO
			, CNDDT_ID
			, STARE_ANSR
			, ACQS_SCR
			, QSTN_SEQ
			, FDBK_CTS
			, FDBK_DTTM
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
    	) VALUES (
    		  #{examCd}
    		, #{examQstnSn}
    		, #{stdNo}
    		, #{qstnNo}
    		, #{subNo}
    		, #{stareAnsr}
    		, #{getScore}
    		, #{examOdr}
    		, #{fdbkCts}
    		, #{fdbkDttm}
    		, #{rgtrId}
    		, FN_DTTM()
    		, #{mdfrId}
    		, FN_DTTM()
    	)

		/*
             SQL ID : ExamStarePaperDAO.insertExamStarePaperBatch
            	 설  명 : 응시 시험지 등록 일괄
         */
        INSERT ALL

    	INTO TB_LMS_EXAM_STARE_PAPER (
    		  EXAM_ID
			, EXAM_QSTN_NO
			, STD_ID
			, QSTN_SEQNO
			, CNDDT_ID
			, STARE_ANSR
			, ACQS_SCR
			, QSTN_SEQ
			, FDBK_CTS
			, FDBK_DTTM
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
    	) VALUES (
    		  #{item.examCd}
    		, #{item.examQstnSn}
    		, #{item.stdNo}
    		, #{item.qstnNo}
    		, #{item.subNo}
    		, #{item.stareAnsr}
    		, #{item.getScore}
    		, #{item.examOdr}
    		, #{item.fdbkCts}
    		, #{item.fdbkDttm}
    		, #{item.rgtrId}
    		, FN_DTTM()
    		, #{item.mdfrId}
    		, FN_DTTM()
    	)

    	SELECT * FROM SYS.DUAL

mapper.select:
/* SQL ID : ExamStarePaperDAO.paperQstnlist 설 명 : 시험지 문제 목록 조회 */ SELECT A.EXAM_ID AS examCd , A.EXAM_QSTN_NO AS examQstnSn , A.STD_ID AS stdNo , A.QSTN_SEQNO AS qstnNo , A.CNDDT_ID AS subNo , A.STARE_ANSR AS stareAnsr , A.ACQS_SCR AS getScore , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm , A.QSTN_SEQ AS examOdr , A.FDBK_CTS AS fdbkCts , A.FDBK_DTTM AS fdbkDttm , B.TTL AS TTL , B.QSTN_CTS AS qstnCts , B.QSTN_EXPLN AS qstnExpl , B.MLT_CRANSYN AS multiRgtChoiceYn , B.MLT_CRANS_TYCD AS multiRgtChoiceTypeCd , B.QSTN_TYCD AS qstnTypeCd , B.QSTN_DFCTLV AS qstnDiff , B.QSTN_SCR AS qstnScore , B.EXMPL01 AS empl1 , B.EXMPL02 AS empl2 , B.EXMPL03 AS empl3 , B.EXMPL04 AS empl4 , B.EXMPL05 AS empl5 , B.EXMPL06 AS empl6 , B.EXMPL07 AS empl7 , B.EXMPL08 AS empl8 , B.EXMPL09 AS empl9 , B.EXMPL10 AS empl10 , B.RGT_ANSR1 AS rgtAnsr1 , B.RGT_ANSR2 AS rgtAnsr2 , B.RGT_ANSR3 AS rgtAnsr3 , B.CRANS4 AS rgtAnsr4 , B.CRANS5 AS rgtAnsr5 , B.WHOL_CRANS_PROCYN AS errorAnsrYn , (CASE WHEN (NVL(LENGTH(TRIM(B.EXMPL01)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(B.EXMPL02)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(B.EXMPL03)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(B.EXMPL04)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(B.EXMPL05)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(B.EXMPL06)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(B.EXMPL07)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(B.EXMPL08)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(B.EXMPL09)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(B.EXMPL10)),0) = 0) THEN 0 ELSE 1 END ) AS emplCnt FROM TB_LMS_EXAM_STARE_PAPER A JOIN TB_LMS_EXAM_QSTN B ON A.EXAM_ID = B.EXAM_ID AND A.EXAM_QSTN_NO = B.EXAM_QSTN_NO WHERE 1=1
AND A.EXAM_ID = #{examCd} AND A.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE ATNDLC_STSCD = 'S' AND SBJCT_ID = (SELECT SBJCT_ID FROM TB_LMS_EXAM_CRE_CRS_RLTN WHERE EXAM_ID = #{examCd}))
AND A.EXAM_QSTN_NO = #{examQstnSn}
AND A.QSTN_SEQNO = #{qstnNo}
AND A.CNDDT_ID = #{subNo}
AND A.STD_ID = #{stdNo}
ORDER BY A.QSTN_SEQNO, A.CNDDT_ID

/* SQL ID : ExamStarePaperDAO.listStdStarePaper 설 명 : 학생의 시험지 문제 조회 */ SELECT D.EXAM_ID , D.EXAM_QSTN_NO , D.STD_ID , D.QSTN_SEQNO , D.CNDDT_ID , D.STARE_ANSR , D.QSTN_SEQ , D.ACQS_SCR , D.FDBK_CTS , D.FDBK_DTTM , D.TTL , D.QSTN_CTS , D.QSTN_EXPLN , D.MLT_CRANSYN , D.MLT_CRANS_TYCD , D.QSTN_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = D.ORG_ID AND CTGRCD = 'QSTN_TYCD' AND CD = D.QSTN_TYCD AND ROWNUM = 1) AS QSTN_TYPE_NM , D.QSTN_DFCTLV , D.WHOL_CRANS_PROCYN , D.EXMPL01 , D.EXMPL02 , D.EXMPL03 , D.EXMPL04 , D.EXMPL05 , D.EXMPL06 , D.EXMPL07 , D.EXMPL08 , D.EXMPL09 , D.EXMPL10 , D.RGT_ANSR1 , D.RGT_ANSR2 , D.RGT_ANSR3 , D.CRANS4 , D.CRANS5 , D.QSTN_SCR , CASE WHEN ROW_NUMBER() OVER(ORDER BY D.COMP_ST, D.QSTN_SEQNO) = 1 THEN 'Y' ELSE 'N' END AS CURR_YN ,( CASE WHEN (NVL(LENGTH(TRIM(D.EXMPL01)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(D.EXMPL02)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(D.EXMPL03)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(D.EXMPL04)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(D.EXMPL05)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(D.EXMPL06)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(D.EXMPL07)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(D.EXMPL08)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(D.EXMPL09)),0) = 0) THEN 0 ELSE 1 END + CASE WHEN (NVL(LENGTH(TRIM(D.EXMPL10)),0) = 0) THEN 0 ELSE 1 END) AS EMPL_CNT , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = D.RGTR_ID) AS RGTRNM , (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = D.RGTR_ID) AS REG_ID , D.RGTR_ID , D.REG_PHT_FILE FROM ( SELECT A.EXAM_ID , A.EXAM_QSTN_NO , A.STD_ID , A.QSTN_SEQNO , B.CNDDT_ID , A.STARE_ANSR , A.QSTN_SEQ , A.ACQS_SCR , A.FDBK_CTS , A.FDBK_DTTM , CASE WHEN A.STARE_ANSR IS NULL THEN 1 ELSE 2 END AS COMP_ST , B.TTL , B.QSTN_CTS , B.QSTN_EXPLN , B.MLT_CRANSYN , B.MLT_CRANS_TYCD , B.QSTN_TYCD , B.QSTN_DFCTLV , B.QSTN_SCR , B.WHOL_CRANS_PROCYN , B.EXMPL01 , B.EXMPL02 , B.EXMPL03 , B.EXMPL04 , B.EXMPL05 , B.EXMPL06 , B.EXMPL07 , B.EXMPL08 , B.EXMPL09 , B.EXMPL10 , B.RGT_ANSR1 , B.RGT_ANSR2 , B.RGT_ANSR3 , B.CRANS4 , B.CRANS5 , C.ORG_ID , A.RGTR_ID , (SELECT PHT_FILE FROM TB_LMS_USR WHERE USER_ID = A.RGTR_ID) AS REG_PHT_FILE FROM TB_LMS_EXAM_STARE_PAPER A JOIN TB_LMS_EXAM_QSTN B ON A.EXAM_ID = B.EXAM_ID AND A.EXAM_QSTN_NO = B.EXAM_QSTN_NO AND B.DELYN = 'N' JOIN TB_LMS_EXAM_BSC C ON C.EXAM_ID = B.EXAM_ID WHERE B.EXAM_ID = #{examCd}
AND A.STD_ID = #{stdNo}
AND A.EXAM_QSTN_NO in
#{item}
GROUP BY A.EXAM_ID, A.EXAM_QSTN_NO
) D
ORDER BY D.STD_ID ASC, D.QSTN_SEQNO ASC, D.CNDDT_ID ASC
ORDER BY D.QSTN_SEQNO,D.CNDDT_ID

/* SQL ID : ExamStarePaperDAO.listStdStarePaperNotExists 설 명 : 학생의 시험지 문제 등록 체크 */ WITH STD_T AS ( SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID IN
#{item}
) SELECT A.STD_ID FROM STD_T A WHERE STD_ID NOT IN ( SELECT A.STD_ID FROM ( SELECT A.STD_ID FROM TB_LMS_EXAM_STARE_PAPER A JOIN TB_LMS_EXAM_QSTN B ON A.EXAM_ID = B.EXAM_ID AND A.EXAM_QSTN_NO = B.EXAM_QSTN_NO AND B.DELYN = 'N' JOIN TB_LMS_EXAM_BSC C ON C.EXAM_ID = B.EXAM_ID AND C.DELYN = 'N' AND C.EXAM_ID = #{examCd} WHERE A.STD_ID IN ( SELECT STD_ID FROM STD_T ) GROUP BY A.STD_ID ) A )

mapper.delete:
	/*
	 	SQL ID : ExamStarePaperDAO.deleteStarePaper
	 	설  명 : 시험지 문제 삭제
 	*/
	DELETE FROM TB_LMS_EXAM_STARE_PAPER
	WHERE 1=1
	AND EXAM_ID		 = #{examCd}   
	AND EXAM_QSTN_NO = #{examQstnSn}   
	AND STD_ID		 = #{stdNo}

mapper.update:
	/*
	 	SQL ID : ExamStarePaperDAO.updateStarePaper
	 	설  명 : 시험지 문제 수정
 	*/
	UPDATE TB_LMS_EXAM_STARE_PAPER SET
		  MDFR_ID = #{mdfrId}
		, MOD_DTTM = FN_DTTM()

		, QSTN_SEQNO = #{qstnNo}


		, CNDDT_ID = #{subNo}


		, STARE_ANSR = #{stareAnsr}


		, ACQS_SCR = #{getScore}


		, QSTN_SEQ = #{examOdr}



				, FDBK_CTS = #{fdbkCts}
				, FDBK_DTTM = FN_DTTM()


				, FDBK_CTS = ''
				, FDBK_DTTM = NULL


	 WHERE EXAM_ID = #{examCd}
	   AND EXAM_QSTN_NO = #{examQstnSn}

	   AND STD_ID = #{stdNo}

mapper.delete:
	/*
	 	SQL ID : ExamStarePaperDAO.deleteAll
	 	설  명 : 시험지의 문제 전체 삭제
 	*/
	DELETE FROM TB_LMS_EXAM_STARE_PAPER
	 WHERE EXAM_ID = #{examCd} 
	   AND STD_ID  = #{stdNo}

mapper.update:
        /*
       		SQL ID : ExamStarePaperDAO.updateExamStarePaperInit
         	설  명 : 시험 응시 문항 초기화
        */
        UPDATE TB_LMS_EXAM_STARE_PAPER 
           SET MDFR_ID = #{mdfrId}
             , MOD_DTTM = FN_DTTM()
             , STARE_ANSR = NULL
             , ACQS_SCR = NULL
             , FDBK_CTS	= NULL
			 , FDBK_DTTM = NULL
         WHERE EXAM_ID = #{examCd}
           AND STD_ID = #{stdNo}

     /*
    		SQL ID : ExamStarePaperDAO.updateExamStarePaperTempSave
		 	설  명 : 시험 응시 문항 임시저장
     */
     UPDATE TB_LMS_EXAM_STARE_PAPER 
        SET MDFR_ID = #{mdfrId}
          , MOD_DTTM = FN_DTTM()

          , STARE_ANSR = #{stareAnsr,javaType=String,jdbcType=VARCHAR}


          , ACQS_SCR = #{getScore}

      WHERE EXAM_ID = #{examCd}
        AND STD_ID = #{stdNo}
        AND EXAM_QSTN_NO = #{examQstnSn}

mapper.select:
/* SQL ID : ExamStarePaperDAO.listStdPageing 설 명 : 시험문제 배정된 학습자 리스트 조회 */ WITH RECURSIVE STD_T AS ( SELECT #{stdNos} AS STD_ID ) , COPY_T AS ( SELECT 1 AS N UNION ALL SELECT N + 1 FROM COPY_T, STD_T WHERE N <= LENGTH(STD_ID) - LENGTH(REPLACE(STD_ID, ',', '')) ) SELECT ROW_NUMBER() OVER(ORDER BY B.USER_ID DESC) AS lineNo , A.EXAM_ID AS examCd , A.EXAM_QSTN_NO AS examQstnSn , IFNULL(( SELECT AA.ACQS_TOT_SCR FROM TB_LMS_EXAM_STARE AA WHERE AA.EXAM_ID = A.EXAM_ID AND AA.STD_ID = A.STD_ID ), 0) AS totGetScore , IFNULL(( SELECT SUM(AA.ACQS_SCR) FROM TB_LMS_EXAM_STARE_PAPER AA WHERE AA.EXAM_ID = A.EXAM_ID AND AA.STD_ID = A.STD_ID ), 0) AS stareScore , A.ACQS_SCR AS getScore , IFNULL(( SELECT CC.QSTN_SCR FROM TB_LMS_EXAM_QSTN CC WHERE CC.EXAM_ID = A.EXAM_ID AND CC.EXAM_QSTN_NO = A.EXAM_QSTN_NO ), 0) AS qstnScore , A.STARE_ANSR AS stareAnsr , IFNULL(( SELECT CC.RGT_ANSR1 FROM TB_LMS_EXAM_QSTN CC WHERE CC.EXAM_ID = A.EXAM_ID AND CC.EXAM_QSTN_NO = A.EXAM_QSTN_NO ), 0) AS rgtAnsr1 , IFNULL(( SELECT CC.RGT_ANSR2 FROM TB_LMS_EXAM_QSTN CC WHERE CC.EXAM_ID = A.EXAM_ID AND CC.EXAM_QSTN_NO = A.EXAM_QSTN_NO ), 0) AS rgtAnsr2 , IFNULL(( SELECT CC.RGT_ANSR3 FROM TB_LMS_EXAM_QSTN CC WHERE CC.EXAM_ID = A.EXAM_ID AND CC.EXAM_QSTN_NO = A.EXAM_QSTN_NO ), 0) AS rgtAnsr3 , IFNULL(( SELECT CC.CRANS4 FROM TB_LMS_EXAM_QSTN CC WHERE CC.EXAM_ID = A.EXAM_ID AND CC.EXAM_QSTN_NO = A.EXAM_QSTN_NO ), 0) AS rgtAnsr4 , IFNULL(( SELECT CC.CRANS5 FROM TB_LMS_EXAM_QSTN CC WHERE CC.EXAM_ID = A.EXAM_ID AND CC.EXAM_QSTN_NO = A.EXAM_QSTN_NO ), 0) AS rgtAnsr5 , A.QSTN_SEQ AS examOdr , A.STD_ID AS stdNo , B.USER_ID AS userId , C.USERNM AS userNm , C.DEPTNM AS deptNm , D.USER_ID AS userId , IF(T.STD_ID IS NOT NULL, 'Y', 'N') AS checkYn , COUNT(1) OVER() AS totalCnt FROM TB_LMS_EXAM_STARE_PAPER A JOIN TB_LMS_ATNDLC_SBJCT B ON A.STD_ID = B.STD_ID JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID JOIN TB_LMS_USER_ACNT D ON C.USER_ID = D.USER_ID LEFT JOIN ( SELECT DISTINCT SUBSTRING_INDEX(SUBSTRING_INDEX(STD_ID, ',', N), ',', -1) AS STD_ID FROM COPY_T, STD_T ) T ON A.STD_ID = T.STD_ID WHERE A.EXAM_ID = #{examCd} AND A.EXAM_QSTN_NO = #{examQstnSn}
AND ( C.USERNM LIKE CONCAT('%', #{searchValue}, '%') COLLATE utf8mb4_general_ci OR C.DEPTNM LIKE CONCAT('%', #{searchValue}, '%') COLLATE utf8mb4_general_ci OR D.USER_ID LIKE CONCAT('%', #{searchValue}, '%') COLLATE utf8mb4_general_ci )
GROUP BY A.EXAM_ID , A.STD_ID ORDER BY B.USER_ID LIMIT #{firstIndex}, #{listScale}

/* SQL ID : ExamStarePaperDAO.select 설 명 : 시험지 문제 조회 */ SELECT A.EXAM_ID AS examCd , A.EXAM_QSTN_NO AS examQstnSn , A.STD_ID AS stdNo , A.QSTN_SEQNO AS qstnNo , A.CNDDT_ID AS subNo , A.STARE_ANSR AS stareAnsr , A.ACQS_SCR AS getScore , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm , A.QSTN_SEQ AS examOdr , A.FDBK_CTS AS fdbkCts , A.FDBK_DTTM AS fdbkDttm FROM TB_LMS_EXAM_STARE_PAPER A WHERE 1=1 AND EXAM_ID = #{examCd}
AND EXAM_QSTN_NO = #{examQstnSn}
AND A.QSTN_SEQNO = #{qstnNo}
AND A.CNDDT_ID = #{subNo}
AND A.STD_ID = #{stdNo}

mapper.delete:
	/*
	 	SQL ID : ExamStarePaperDAO.deleteAllPaper
	 	설  명 : 시험지 문제 전체 삭제
 	*/
 	DELETE FROM TB_LMS_EXAM_STARE_PAPER
 	 WHERE EXAM_ID = #{examCd}
